mapper.update:
UPDATE comment
content = #{content}, like_count = #{likeCount}, reply_count = #{replyCount}, reply_to_user_id = #{replyToUserId}, root_comment_id = #{rootCommentId}, updated_at = CURRENT_TIMESTAMP
WHERE comment_id = #{commentId}

mapper.select:
SELECT 
FROM comment
WHERE root_comment_id = #{rootCommentId}
  AND comment_id != #{rootCommentId}


        ORDER BY created_at DESC, comment_id DESC


        ORDER BY created_at ASC, comment_id ASC


LIMIT #{pageSize} OFFSET #{offset}

SELECT comment_id, root_comment_id, note_id, author_id, parent_id, reply_to_user_id, content, like_count, reply_count, created_at, updated_at FROM ( SELECT c.comment_id, c.root_comment_id, c.note_id, c.author_id, c.parent_id, c.reply_to_user_id, c.content, c.like_count, c.reply_count, c.created_at, c.updated_at, ROW_NUMBER() OVER (PARTITION BY c.root_comment_id ORDER BY c.created_at ASC, c.comment_id ASC) AS rn FROM comment c WHERE c.root_comment_id IN
#{rootCommentId}
AND c.comment_id != c.root_comment_id ) t WHERE t.rn <= #{limitPerRoot} ORDER BY t.root_comment_id ASC, t.created_at ASC, t.comment_id ASC

SELECT COUNT(*)
FROM comment
WHERE root_comment_id = #{rootCommentId}
  AND comment_id != #{rootCommentId}

SELECT NULL AS comment_id, root_comment_id, NULL AS note_id, NULL AS author_id, NULL AS parent_id, NULL AS reply_to_user_id, NULL AS content, NULL AS like_count, COUNT(*) AS reply_count, NULL AS created_at, NULL AS updated_at FROM comment WHERE root_comment_id IN
#{rootCommentId}
AND comment_id != root_comment_id GROUP BY root_comment_id

SELECT * FROM comment

    AND note_id = #{params.noteId}
    AND author_id = #{params.authorId}

ORDER BY created_at DESC
LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(*) FROM comment

    AND note_id = #{params.noteId}
    AND parent_id = #{params.parentId}
    AND author_id = #{params.authorId}
